import { Permissao } from './Permissao';
import { DadosUsuario, Usuario } from './Usuario';

export type DadosProfessor = DadosUsuario & {
  formacao?: string;
};

export class Professor extends Usuario {
  formacao?: string;

  constructor(dados: DadosProfessor) {
    super({ ...dados, permissao: Permissao.Professor });
    this.formacao = dados.formacao;
  }

  podeGerenciarMaterias(): boolean {
    return true;
  }

  podeVisualizarMaterias(): boolean {
    return true;
  }
}
